package transport

import (
	"fmt"
	"sync"
)

// registry are the protocols supported by default.
var (
	registry = map[string]Transport{}
	mtx      sync.RWMutex
)

// Register adds or modifies an existing protocol.
// Equivalent to client.InstallProtocol in go-git before V6.
func Register(protocol string, c Transport) {
	mtx.Lock()
	registry[protocol] = c
	mtx.Unlock()
}

// Unregister removes a protocol from the list of supported protocols.
func Unregister(scheme string) {
	mtx.Lock()
	delete(registry, scheme)
	mtx.Unlock()
}

// Get returns the appropriate client for the given protocol.
func Get(p string) (Transport, error) {
	mtx.RLock()
	defer mtx.RUnlock()
	f, ok := registry[p]
	if !ok {
		return nil, fmt.Errorf("unsupported scheme %q", p)
	}

	if f == nil {
		return nil, fmt.Errorf("malformed client for scheme %q, client is defined as nil", p)
	}
	return f, nil
}

package server

import (
	"io"

	"github.com/go-git/go-git/v6/internal/server/http"
	"github.com/go-git/go-git/v6/plumbing/transport"
)

// GitServer represents a git transport server that can be started and stopped.
type GitServer interface {
	Start() (string, error)
	io.Closer
}

// All returns all available git server implementations backed by the given loader.
func All(l transport.Loader) []GitServer {
	servers := []GitServer{}
	if srv, err := http.FromLoader(l); err == nil {
		servers = append(servers, srv)
	}

	return servers
}
// Package server provides test helpers for running in-process git servers.
package server

import (
	"fmt"
	"testing"

	"github.com/go-git/go-billy/v6"
	fixtures "github.com/go-git/go-git-fixtures/v5"

	"github.com/go-git/go-git/v6/plumbing/transport"
	"github.com/go-git/go-git/v6/storage"
	"github.com/go-git/go-git/v6/storage/filesystem"
)

type fixturesLoader struct {
	dot billy.Filesystem
}

var _ transport.Loader = &fixturesLoader{}

func (f *fixturesLoader) Load(_ *transport.Endpoint) (storage.Storer, error) {
	if f.dot == nil {
		return nil, fmt.Errorf("cannot load endpoint: fixture not set")
	}

	// Re-use the pre-extracted filesystem for every request. The server is
	// read-only (upload-pack only), so sharing the underlying billy.Filesystem
	// across storage instances is safe and avoids re-extracting the tgz on
	// every clone or fetch.
	return filesystem.NewStorage(f.dot, nil), nil
}

// Loader returns a transport.Loader backed by fix. The fixture's .git directory
// is extracted exactly once (into memory) when Loader is called; all subsequent
// server requests share the same extracted filesystem.
func Loader(t testing.TB, fix *fixtures.Fixture) transport.Loader {
	t.Helper()
	if fix == nil {
		t.Fatal("Loader: fixture must not be nil")
	}
	dot := fix.DotGit(fixtures.WithMemFS())
	return &fixturesLoader{dot: dot}
}

