38	// LookupEntireDBCredential looks up credentials from the Entire token store.
39	// Returns (username, password, true, nil) on success, ("", "", false, nil) when
40	// no credential is configured, or ("", "", false, err) when a credential exists
41	// but refresh failed (issue #7).
42	func LookupEntireDBCredential(raw Endpoint, ep *transport.Endpoint) (string, string, bool, error) {
43		if ep == nil || ep.Host == "" {
44			return "", "", false, nil
45		}
46		credHost := endpointCredentialHost(ep)
47		token, err := lookupEntireDBToken(credHost, endpointBaseURL(ep), raw.SkipTLSVerify)
48		if err != nil {
49			return "", "", false, err
50		}
51		if token == "" {
52			return "", "", false, nil
53		}
54		username := raw.Username
55		if username == "" {
56			username = "git"
57		}
58		return username, token, true, nil
59	}
60	
61	func endpointBaseURL(ep *transport.Endpoint) string {
62		if ep == nil || ep.Host == "" {
63			return ""
64		}
65		scheme := ep.Protocol
66		if scheme == "" {
67			scheme = "https"
68		}
69		host := ep.Host
70		if ep.Port > 0 {
71			host = fmt.Sprintf("%s:%d", host, ep.Port)
72		}
73		return scheme + "://" + host
74	}
75	
76	func endpointCredentialHost(ep *transport.Endpoint) string {
77		if ep == nil {
78			return ""
79		}
80		if ep.Port > 0 {
81			return fmt.Sprintf("%s:%d", ep.Host, ep.Port)
82		}
83		return ep.Host
84	}
