86	func lookupEntireDBToken(host, baseURL string, skipTLS bool) (string, error) {
87		configDir := os.Getenv("ENTIRE_CONFIG_DIR")
88		if configDir == "" {
89			home, err := os.UserHomeDir()
90			if err != nil {
91				return "", nil // no config dir, not an error
92			}
93			configDir = filepath.Join(home, ".config", "entire")
94		}
95	
96		username, ok := loadEntireDBActiveUser(host, configDir)
97		if !ok || username == "" {
98			return "", nil
99		}
100		return getTokenWithRefresh(context.Background(), host, username, baseURL, skipTLS)
101	}
102	
103	func loadEntireDBActiveUser(host, configDir string) (string, bool) {
104		data, err := os.ReadFile(filepath.Join(configDir, "hosts.json"))
105		if err != nil {
106			return "", false
107		}
108		var hosts map[string]*entireAuthHostInfo
109		if err := json.Unmarshal(data, &hosts); err != nil {
110			return "", false
111		}
112		info := hosts[host]
113		if info == nil || info.ActiveUser == "" {
114			return "", false
115		}
116		return info.ActiveUser, true
117	}
