119	// getTokenWithRefresh retrieves a token, refreshing it if expired.
120	// On refresh failure, returns the stale token with a nil error rather than
121	// propagating the refresh error silently (issue #7).
122	func getTokenWithRefresh(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
123		encoded, err := ReadStoredToken(credentialService(host), username)
124		if err != nil {
125			// "Not found" means no credential is configured — not an error.
126			// Only propagate actual storage failures.
127			if isNotFound(err) {
128				return "", nil
129			}
130			return "", err
131		}
132		token, expiresAt := decodeTokenWithExpiration(encoded)
133		if token == "" {
134			return "", nil
135		}
136		if !tokenExpiredOrExpiring(expiresAt) {
137			return token, nil
138		}
139		refreshed, err := refreshAccessToken(ctx, host, username, baseURL, skipTLS)
140		if err != nil {
141			// Issue #7: surface refresh failure explicitly instead of silently reusing stale token.
142			return "", fmt.Errorf("token expired and refresh failed for %s@%s: %w", username, host, err)
143		}
144		return refreshed, nil
145	}
146	
147	func decodeTokenWithExpiration(encoded string) (string, time.Time) {
148		idx := strings.LastIndex(encoded, "|")
149		if idx == -1 {
150			return encoded, time.Time{}
151		}
152		token := encoded[:idx]
153		ts, err := strconv.ParseInt(encoded[idx+1:], 10, 64)
154		if err != nil {
155			return encoded, time.Time{}
156		}
157		return token, time.Unix(ts, 0)
158	}
159	
160	func tokenExpiredOrExpiring(expiresAt time.Time) bool {
161		if expiresAt.IsZero() {
162			return true
163		}
164		return time.Now().Add(5 * time.Minute).After(expiresAt)
165	}
166	
167	func refreshAccessToken(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
168		refreshToken, err := ReadStoredToken(credentialService(host)+":refresh", username)
169		if err != nil {
170			return "", err
171		}
172		if refreshToken == "" || baseURL == "" {
173			return "", errors.New("missing refresh token or base url")
174		}
175	
176		form := url.Values{}
177		form.Set("grant_type", "refresh_token")
178		form.Set("refresh_token", refreshToken)
179		form.Set("client_id", entireCLIClientID)
180	
181		req, err := http.NewRequestWithContext(ctx, http.MethodPost, strings.TrimRight(baseURL, "/")+"/oauth/token", strings.NewReader(form.Encode()))
182		if err != nil {
183			return "", err
184		}
185		req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
186	
187		client := &http.Client{
188			Timeout: 30 * time.Second,
189			Transport: &http.Transport{
190				TLSClientConfig: &tls.Config{InsecureSkipVerify: skipTLS}, //nolint:gosec
191			},
192		}
193		resp, err := client.Do(req)
194		if err != nil {
195			return "", err
196		}
197		defer resp.Body.Close()
198		if resp.StatusCode != http.StatusOK {
199			return "", fmt.Errorf("refresh failed with status %d", resp.StatusCode)
200		}
201	
202		var tokenResp oauthTokenResponse
203		if err := json.NewDecoder(resp.Body).Decode(&tokenResp); err != nil {
204			return "", err
205		}
206		if tokenResp.AccessToken == "" {
207			return "", errors.New("empty access token in refresh response")
208		}
209	
210		if err := WriteStoredToken(
211			credentialService(host),
212			username,
213			encodeTokenWithExpiration(tokenResp.AccessToken, tokenResp.ExpiresIn),
214		); err != nil {
215			return "", err
216		}
217		if tokenResp.RefreshToken != "" {
218			_ = WriteStoredToken(credentialService(host)+":refresh", username, tokenResp.RefreshToken)
219		}
220		return tokenResp.AccessToken, nil
221	}
222	
223	func encodeTokenWithExpiration(token string, expiresIn int64) string {
224		return fmt.Sprintf("%s|%d", token, time.Now().Unix()+expiresIn)
225	}
226	
227	func credentialService(host string) string {
228		return "entire:" + host
229	}
