29	// FetchFeatures summarizes negotiated source fetch features used by strategies.
30	type FetchFeatures struct {
31		Filter     bool
32		IncludeTag bool
33	}
34	
35	func (s *RefService) FetchFeatures() FetchFeatures {
36		if s == nil || s.Protocol != "v2" || s.V2Caps == nil {
37			return FetchFeatures{}
38		}
39		return FetchFeatures{
40			Filter:     s.V2Caps.FetchSupports("filter"),
41			IncludeTag: s.V2Caps.FetchSupports("include-tag"),
42		}
43	}
