45	// SupportsBootstrapBatch centralizes the source-side capability check for the
46	// batched bootstrap strategy.
47	func (s *RefService) SupportsBootstrapBatch() bool {
48		return s != nil && s.Protocol == "v2" && s.FetchFeatures().Filter
49	}
