51	// FetchToStore fetches objects from source into the given store, using the
52	// appropriate protocol version.
53	func (s *RefService) FetchToStore(
54		ctx context.Context,
55		store storer.Storer,
56		conn *Conn,
57		desired map[plumbing.ReferenceName]DesiredRef,
58		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
59	) error {
60		switch s.Protocol {
61		case "v2":
62			return fetchToStoreV2(ctx, store, conn, s.V2Caps, desired, targetRefs)
63		case "v1":
64			return fetchToStoreV1(ctx, store, conn, s.V1Adv, desired, targetRefs)
65		default:
66			return fmt.Errorf("unsupported source protocol %q", s.Protocol)
67		}
68	}
