88	// FetchCommitGraph fetches only the commit graph (tree:0 filter) for a ref.
89	// Requires v2 with filter support.
90	func (s *RefService) FetchCommitGraph(
91		ctx context.Context,
92		store storer.Storer,
93		conn *Conn,
94		ref DesiredRef,
95	) error {
96		if s.Protocol != "v2" {
97			return fmt.Errorf("commit graph fetch requires protocol v2")
98		}
99		if !s.V2Caps.FetchSupports("filter") {
100			return fmt.Errorf("source does not advertise fetch filter support")
101		}
102	
103		cmdArgs := []string{
104			"ofs-delta",
105			"no-progress",
106			"filter tree:0",
107			"want " + ref.SourceHash.String(),
108			"done",
109		}
110		body, err := EncodeCommand("fetch", s.V2Caps.RequestCapabilities(), cmdArgs)
111		if err != nil {
112			return err
113		}
114		reader, err := PostRPCStream(ctx, conn, transport.UploadPackServiceName, body, true, "upload-pack fetch")
115		if err != nil {
116			return err
117		}
118		defer ioutil.CheckClose(reader, &err)
119		return storeV2FetchPack(store, reader)
120	}
