134	// --- V2 fetch implementation ---
135	
136	func fetchToStoreV2(
137		ctx context.Context,
138		store storer.Storer,
139		conn *Conn,
140		caps *V2Capabilities,
141		desired map[plumbing.ReferenceName]DesiredRef,
142		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
143	) error {
144		wants := collectWants(desired)
145		haves := SortedUniqueHashes(refValues(targetRefs))
146		if len(wants) == 0 {
147			return git.NoErrAlreadyUpToDate
148		}
149	
150		cmdArgs := make([]string, 0, len(wants)+len(haves)+4)
151		cmdArgs = append(cmdArgs, "ofs-delta", "no-progress")
152		for _, h := range wants {
153			cmdArgs = append(cmdArgs, "want "+h.String())
154		}
155		for _, h := range haves {
156			cmdArgs = append(cmdArgs, "have "+h.String())
157		}
158		cmdArgs = append(cmdArgs, "done")
159	
160		body, err := EncodeCommand("fetch", caps.RequestCapabilities(), cmdArgs)
161		if err != nil {
162			return err
163		}
164		reader, err := PostRPCStream(ctx, conn, transport.UploadPackServiceName, body, true, "upload-pack fetch")
165		if err != nil {
166			return err
167		}
168		defer ioutil.CheckClose(reader, &err)
169		return storeV2FetchPack(store, reader)
170	}
171	
172	func fetchPackV2(
173		ctx context.Context,
174		conn *Conn,
175		caps *V2Capabilities,
176		desired map[plumbing.ReferenceName]DesiredRef,
177		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
178	) (io.ReadCloser, error) {
179		wants := collectWants(desired)
180		haves := SortedUniqueHashes(refValues(targetRefs))
181		if len(wants) == 0 {
182			return nil, git.NoErrAlreadyUpToDate
183		}
184	
185		cmdArgs := make([]string, 0, len(wants)+len(haves)+4)
186		cmdArgs = append(cmdArgs, "ofs-delta", "no-progress")
187		// Only request include-tag if the server supports it (issue #6).
188		if hasTag(desired) && caps.FetchSupports("include-tag") {
189			cmdArgs = append(cmdArgs, "include-tag")
190		}
191		for _, h := range wants {
192			cmdArgs = append(cmdArgs, "want "+h.String())
193		}
194		for _, h := range haves {
195			cmdArgs = append(cmdArgs, "have "+h.String())
196		}
197		cmdArgs = append(cmdArgs, "done")
198	
199		body, err := EncodeCommand("fetch", caps.RequestCapabilities(), cmdArgs)
200		if err != nil {
201			return nil, err
202		}
203		reader, err := PostRPCStream(ctx, conn, transport.UploadPackServiceName, body, true, "upload-pack fetch")
204		if err != nil {
205			return nil, err
206		}
207		packStream, err := openV2PackStream(reader)
208		if err != nil {
209			_ = reader.Close()
210			return nil, err
211		}
212		return packStream, nil
213	}
214	
215	func storeV2FetchPack(store storer.Storer, r io.Reader) error {
216		reader := NewPacketReader(r)
217		for {
218			kind, payload, err := reader.ReadPacket()
219			if err != nil {
220				if errors.Is(err, io.EOF) {
221					return nil
222				}
223				return fmt.Errorf("decode protocol v2 fetch response: %w", err)
224			}
225			switch kind {
226			case PacketFlush:
227				return nil
228			case PacketDelim, PacketResponseEnd:
229				continue
230			case PacketData:
231				line := string(payload)
232				switch line {
233				case "packfile\n":
234					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader())
235					return packfile.UpdateObjectStorage(store, demux)
236				case "acknowledgments\n", "shallow-info\n":
237					if err := SkipSection(reader); err != nil {
238						return err
239					}
240				default:
241					return fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
242				}
243			}
244		}
245	}
246	
247	func openV2PackStream(body io.ReadCloser) (io.ReadCloser, error) {
248		reader := NewPacketReader(body)
249		for {
250			kind, payload, err := reader.ReadPacket()
251			if err != nil {
252				if errors.Is(err, io.EOF) {
253					return nil, io.ErrUnexpectedEOF
254				}
255				return nil, fmt.Errorf("decode protocol v2 fetch response: %w", err)
256			}
257			switch kind {
258			case PacketFlush:
259				return nil, io.ErrUnexpectedEOF
260			case PacketDelim, PacketResponseEnd:
261				continue
262			case PacketData:
263				line := string(payload)
264				switch line {
265				case "packfile\n":
266					return &wrappedRC{
267						Reader: sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader()),
268						Closer: body,
269					}, nil
270				case "acknowledgments\n", "shallow-info\n":
271					if err := SkipSection(reader); err != nil {
272						return nil, err
273					}
274				default:
275					return nil, fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
276				}
277			}
278		}
279	}
