281	// --- V1 fetch implementation ---
282	
283	func fetchToStoreV1(
284		ctx context.Context,
285		store storer.Storer,
286		conn *Conn,
287		adv *packp.AdvRefs,
288		desired map[plumbing.ReferenceName]DesiredRef,
289		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
290	) error {
291		session, err := conn.Transport.NewUploadPackSession(conn.Endpoint, conn.Auth)
292		if err != nil {
293			return fmt.Errorf("open source upload-pack session: %w", err)
294		}
295		defer session.Close()
296	
297		req := packp.NewUploadPackRequestFromCapabilities(adv.Capabilities)
298		for _, ref := range desired {
299			req.Wants = append(req.Wants, ref.SourceHash)
300		}
301		req.Wants = SortedUniqueHashes(req.Wants)
302		req.Haves = SortedUniqueHashes(refValues(targetRefs))
303		if len(req.Wants) == 0 {
304			return git.NoErrAlreadyUpToDate
305		}
306		if adv.Capabilities.Supports(capability.NoProgress) {
307			_ = req.Capabilities.Set(capability.NoProgress)
308		}
309		if hasTag(desired) && adv.Capabilities.Supports(capability.IncludeTag) {
310			_ = req.Capabilities.Set(capability.IncludeTag)
311		}
312	
313		reader, err := session.UploadPack(ctx, req)
314		if err != nil {
315			if errors.Is(err, transport.ErrEmptyUploadPackRequest) {
316				return git.NoErrAlreadyUpToDate
317			}
318			return fmt.Errorf("source upload-pack: %w", err)
319		}
320		defer ioutil.CheckClose(reader, &err)
321	
322		sbReader := buildSidebandReader(req.Capabilities, reader, nil)
323		return packfile.UpdateObjectStorage(store, sbReader)
324	}
