326	func fetchPackV1(
327		ctx context.Context,
328		conn *Conn,
329		adv *packp.AdvRefs,
330		desired map[plumbing.ReferenceName]DesiredRef,
331		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
332	) (io.ReadCloser, error) {
333		session, err := conn.Transport.NewUploadPackSession(conn.Endpoint, conn.Auth)
334		if err != nil {
335			return nil, fmt.Errorf("open source upload-pack session: %w", err)
336		}
337	
338		req := packp.NewUploadPackRequestFromCapabilities(adv.Capabilities)
339		for _, ref := range desired {
340			req.Wants = append(req.Wants, ref.SourceHash)
341		}
342		req.Wants = SortedUniqueHashes(req.Wants)
343		req.Haves = SortedUniqueHashes(refValues(targetRefs))
344		if len(req.Wants) == 0 {
345			_ = session.Close()
346			return nil, git.NoErrAlreadyUpToDate
347		}
348		if adv.Capabilities.Supports(capability.NoProgress) {
349			_ = req.Capabilities.Set(capability.NoProgress)
350		}
351		if hasTag(desired) && adv.Capabilities.Supports(capability.IncludeTag) {
352			_ = req.Capabilities.Set(capability.IncludeTag)
353		}
354	
355		reader, err := session.UploadPack(ctx, req)
356		if err != nil {
357			_ = session.Close()
358			if errors.Is(err, transport.ErrEmptyUploadPackRequest) {
359				return nil, git.NoErrAlreadyUpToDate
360			}
361			return nil, fmt.Errorf("source upload-pack: %w", err)
362		}
363		return &sessionRC{
364			Reader: buildSidebandReader(req.Capabilities, reader, nil),
365			closeFn: func() error {
366				_ = reader.Close()
367				return session.Close()
368			},
369		}, nil
370	}
