372	// buildSidebandReader wraps a reader with sideband demuxing if the negotiated
373	// capabilities include sideband support. Delegates to PreferredSideband (issue #4).
374	func buildSidebandReader(caps *capability.List, reader io.Reader, progress sideband.Progress) io.Reader {
375		sb := PreferredSideband(caps)
376		if sb == "" {
377			return reader
378		}
379		var t sideband.Type
380		if sb == capability.Sideband64k {
381			t = sideband.Sideband64k
382		} else {
383			t = sideband.Sideband
384		}
385		d := sideband.NewDemuxer(t, reader)
386		d.Progress = progress
387		return d
388	}
