390	// --- helpers ---
391	
392	func collectWants(desired map[plumbing.ReferenceName]DesiredRef) []plumbing.Hash {
393		hashes := make([]plumbing.Hash, 0, len(desired))
394		for _, ref := range desired {
395			hashes = append(hashes, ref.SourceHash)
396		}
397		return SortedUniqueHashes(hashes)
398	}
399	
400	func hasTag(desired map[plumbing.ReferenceName]DesiredRef) bool {
401		for _, ref := range desired {
402			if ref.IsTag {
403				return true
404			}
405		}
406		return false
407	}
408	
409	func refValues(m map[plumbing.ReferenceName]plumbing.Hash) []plumbing.Hash {
410		out := make([]plumbing.Hash, 0, len(m))
411		for _, h := range m {
412			if !h.IsZero() {
413				out = append(out, h)
414			}
415		}
416		return out
417	}
418	
419	// SortedUniqueHashes deduplicates and sorts a hash slice.
420	func SortedUniqueHashes(input []plumbing.Hash) []plumbing.Hash {
421		seen := make(map[plumbing.Hash]struct{}, len(input))
422		out := make([]plumbing.Hash, 0, len(input))
